    { question: '\ub2e4\uc74c \ubb38\uc7a5\uc744 \ubd84\uc0ac\uad6c\ubb38\uc73c\ub85c \ubc14\uafb8\uc2dc\uc624.', context: 'As I didn\'t have any money, I couldn\'t buy the book.', answers: ['Not having any money, I couldn\'t buy the book.', 'Not having any money, I could not buy the book.'] },
    { question: '\ub2e4\uc74c \ub2a5\ub3d9\ud0dc \ubb38\uc7a5\uc744 \uc218\ub3d9\ud0dc\ub85c \ubc14\uafb8\uc2dc\uc624. (4\ud615\uc2dd \uc218\ub3d9\ud0dc)', context: 'She gave me a beautiful gift.', answers: ['I was given a beautiful gift by her.', 'A beautiful gift was given to me by her.', 'I was given a beautiful gift.', 'A beautiful gift was given to me.'] },
    { question: '\ubcf5\ud569\uad00\uacc4\uc0ac\ub97c \uc0ac\uc6a9\ud558\uc5ec \ub2e4\uc74c \uc6b0\ub9ac\ub9d0\uc744 \uc601\uc791\ud558\uc2dc\uc624: "\ub124\uac00 \uc5b8\uc81c \uc624\ub4e0 \ub098\ub294 \ub108\ub97c \uae30\ub2e4\ub9ac\uaca0\ub2e4."', answers: ['Whenever you come, I will wait for you.', 'Whenever you come, I will be waiting for you.'] },
    { question: '\ub2e4\uc74c \uc6b0\ub9ac\ub9d0\uc744 \uc0ac\uc5ed\ub3d9\uc0ac(make)\ub97c \uc0ac\uc6a9\ud558\uc5ec \uc601\uc791\ud558\uc2dc\uc624: "\uadf8 \uc601\ud654\ub294 \ub098\ub97c \uc6b8\uac8c \ub9cc\ub4e4\uc5c8\ub2e4."', answers: ['The movie made me cry.'] },
    { question: '\ub2e4\uc74c \ubb38\uc7a5\uc744 \uac15\uc870\uad6c\ubb38(It is ~ that)\uc744 \uc0ac\uc6a9\ud558\uc5ec \ub2e4\uc2dc \uc4f0\uc2dc\uc624. (\uc2dc\uac04 \uac15\uc870)', context: 'We arrived at the airport at 6 a.m.', answers: ['It was at 6 a.m. that we arrived at the airport.'] }
